var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"끝났어!","JPN":"できた！","ENG":"It's done!","TWN":"好了！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"문제를 일으킨 기판을 교체했으니, 이제 작동할 거야!","JPN":"問題のある基板を交替したから、もう動くはずだよ！","ENG":"I've replaced all the faulty circuit boards, so it should work now!","TWN":"更換了出問題的線路板，現在應該能運作了！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"7번과 8번 수정의 오류 정화 확인…! 정상적으로 작동합니다!","JPN":"7番と8番水晶のエラー浄化を確認……！　正常に作動しています！","ENG":"Crystals no. 7 and 8's error correction confirmed...! Operating as normal!","TWN":"確認修正了7號和8號水晶的錯誤…！正常運作了！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"다른 보조장치들도 이상 없습니다!","JPN":"他の補助装置も異常ありません！","ENG":"The auxiliary devices are also good!","TWN":"其他輔助裝置也沒有問題！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"중앙 동력 가동. 고정 좌표로 도약 관문 활성화.","JPN":"中央動力稼働。固定座標で跳躍関門を活性化。","ENG":"Central power in operation. Activating space jump gateway with the fixed coordinates.","TWN":"啟動中央動力，啟動固定座標的躍遷門。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"도약 관문 활성화…!","JPN":"跳躍関門を活性化……！","ENG":"Gateway activated...!","TWN":"躍遷門啟動…！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"관문의 가시파장에 낙원의 풍경이 잡힙니다…! 연결이 성공했어요…!","JPN":"関門の可視波長に楽園の姿を捉えました……！　連結成功です……！","ENG":"The visible wavelengths are displaying the Promised Land's scenery...! The link was a success...!","TWN":"門的可見波長捕捉到了樂園的景象…！連接成功了…！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"낙원이다!","JPN":"楽園だ！","ENG":"It's the Promised Land!","TWN":"是樂園！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"됐어! 성공했다고!","JPN":"やった！　成功したぞ！","ENG":"We did it! Success!","TWN":"好了！成功了！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아직 기뻐하긴 일러.","JPN":"まだ喜ぶには早いわ。","ENG":"It is too early to celebrate.","TWN":"現在高興還太早。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그루터기의 모두를 전송시키는 게 원래 목적이었지만, 우리가 가진 적철이 그만큼 여유롭진 않아.","JPN":"切り株のみんなを伝送させるのが最初の目的だったけど、アタシの持つ赤鉄だけじゃ足りない。","ENG":"Our original plan was to migrate everyone in the Stump, but we currently do not have enough Violarite.","TWN":"原本的目的是傳送木墩所有的成員，但我們手頭的赤鐵並不充裕。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"…그 말씀이 맞습니다.","JPN":"……おっしゃる通りです。","ENG":"...That is correct.","TWN":"…您說得沒錯。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"지금의 저희 기술력으론… 성인 다섯 명 정도를 전송하는 게 한계로군요.","JPN":"今の私たちの技術力では……大人を5人ほど伝送するのが限界ですね。","ENG":"With our current technology... we will only be able to send about five adults through.","TWN":"以我們現在的技術…最多只能傳送五個成年人。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"고작… 다섯 명…?","JPN":"たったの……5人……？","ENG":"Only... five...?","TWN":"僅僅…五個人…？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"그 오랜 세월 끝에 얻어낸 결과가 이 정도인 건가.","JPN":"この長い研究の果てに得た結果がこれか。","ENG":"After all these years, is this all that we have achieved?","TWN":"經過這麼多年的努力，結果就只有這點嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"효율을 개선하려 노력했지만… 이게 최선이었습니다.","JPN":"改善しようと頑張ったのですが……これが精一杯でした。","ENG":"We tried to improve its efficiency, but... this was the best we could do.","TWN":"雖然努力提高了效率…但這已經是極限了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"전부 제 역량이 부족한 탓이예요.","JPN":"すべて私の力不足のせいです。","ENG":"It is all because of my lack of capabilities.","TWN":"都是因為我能力不足。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"자책은 미뤄둬. 우리가 종말에 쫓기는 건 그 누구의 책임도 아니야.","JPN":"自分を攻めるのはよしなさい。アタシたちが終末に追われているのは誰のせいでもないわ。","ENG":"Put off blaming yourself for later. It is no one's fault that the end of the world is near.","TWN":"先別自責。我們被末日追趕，這不是任何人的錯。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그리고 인원은 좀 더 늘릴 방법이 있어.","JPN":"それに、送られる人をもう少し増やす方法があるの。","ENG":"Also, there is a way to increase the number of people.","TWN":"而且肯定還有辦法來增加人數。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"도약에 필요한 에너지는 사람의 수가 아닌 질량에 비례하니까.","JPN":"跳躍に必要なエネルギーは人の数ではなく、質量に比例するから。","ENG":"The energy required for the jump depends not on the number of people, but the mass.","TWN":"躍遷所需的能量，是按品質而不是人數來計算的。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"…그렇겠군요.","JPN":"……そうですね。","ENG":"...I see.","TWN":"…原來如此。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"아이들을 데려오겠습니다.","JPN":"子どもたちを連れてきます。","ENG":"I will bring the children.","TWN":"我去帶孩子們過來。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"음…?","JPN":"む……？","ENG":"Mm...?","TWN":"嗯…？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"이봐! 병기마가 돌아온다! 관문을 열어!","JPN":"おい！　兵器馬が戻ってきたぞ！　関門を開けろ！","ENG":"Look! The carriage is back! Open the gates!","TWN":"喂！調查團回來了！快開門！"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"헉… 헉…","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼…呼…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"키안 영감님? 혼자 돌아오신 겁니까? 게다가 그 상처는…","JPN":"キアンさん？　一人で戻ってきたんですか？　それに、その怪我は……","ENG":"Kian? Why are you alone? And those injuries...","TWN":"奇恩爺爺？你一個人回來了？而且還受了傷…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"곧 마왕군이 올 걸세! 이 적철로 서둘러 모든 방벽을 가동하게!","JPN":"すぐ魔王軍が来る！　この赤鉄で今すぐすべての防壁を稼働させるんだ！","ENG":"The Demon Lord's army will soon be here! Use this Violarite and quickly activate all the barriers!","TWN":"魔王的軍隊馬上就要來了！趕緊用這裡的赤鐵啟動所有屏障！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"아… 알겠습니다!","JPN":"わ……わかりました！","ENG":"U-understood!","TWN":"好…我知道了！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"그럼… 함께 갔던 다른 단원들은 어떻게 된 거죠?","JPN":"では……一緒に出発した他の団員たちはどうなったのですか？","ENG":"Then... what about the others who went with you?","TWN":"那…和你一起去的其他成員怎麼樣了？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"터무니없이 강한 마물과 마주쳤네. 모두 당했어.","JPN":"とんでもなく強い魔物と遭遇した。みんなやられてしまった。","ENG":"We encountered an absurdly strong monster, and everyone was killed.","TWN":"遇到了極其強大的怪物。全軍覆沒了…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"그렇다면 성자님도…?","JPN":"では、聖者様も……？","ENG":"Even the Helgon...?","TWN":"那麼聖者也…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"루 양은… 적철을 전달하기 위해 나를 먼저 보낸 걸세.","JPN":"ルーさんは……私に赤鉄を届けさせるため、一人で魔物の相手を……","ENG":"Ms. Lugh... chose to stay and sent me to deliver the Violarite.","TWN":"露為了拖住怪物，先讓我回來。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"면목이 없군.","JPN":"面目ない。","ENG":"I am ashamed.","TWN":"真是慚愧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"…그렇군요.","JPN":"……そうですか。","ENG":"...I see.","TWN":"…我明白了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"방금 전, 제단에서 소식을 전해 받았습니다.","JPN":"先ほど、祭壇から知らせが来ました。","ENG":"We just got word from the altar.","TWN":"剛剛從祭壇收到消息。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"낙원문의 가동이 성공해, 선별된 아이들을 먼저 보낸다고 하더군요.","JPN":"楽園の門の稼働に成功し、選別された子どもたちを先に送るそうです。","ENG":"Avalon's Gate has been successfully activated, and they are sending the children first.","TWN":"門已經成功啟動了，選中的孩子們會先被送走。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그래… 다른 세계로 가는 길이 열렸단 사실만으로도 기적인 셈이지.","JPN":"そうか……別の世界へと道が開けたということだけでも奇跡に等しい。","ENG":"Right... it is a miracle just knowing that a path to a new world has been opened.","TWN":"好…好…僅僅是通往另一個世界的道路打開，就已經是個奇蹟了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"아이들을 전송하기까지, 시간은 얼마나 필요하다고 하던가?","JPN":"子どもたちを送るまで、どれくらいかかる？","ENG":"How much time did they say they would need to send all the children?","TWN":"傳送孩子們需要多長時間？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"반나절이면 충분할 거라 듣긴 했지만…","JPN":"半日で十分だと聞きましたが……","ENG":"They say that half a day would be enough…","TWN":"聽說半天就夠了…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"하늘이 이렇게 어두우니, 남은 시간을 헤아리긴 어렵겠군요.","JPN":"こうも空が暗いと、時間を計算するのは難しいでしょうね。","ENG":"But it will be difficult to assume how much time will have passed with the sky this dark.","TWN":"天這麼黑，很難估算剩下的時間…"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그런 고민은 필요없네.","JPN":"そんなことで悩む必要はない。","ENG":"No need to worry about that.","TWN":"不用擔心這個。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"우린 놈들이 물러날 때까지 버텨낼 테니까.","JPN":"私たちは必ず、耐えてみせる。","ENG":"We're going to hold this place until those monsters retreat.","TWN":"我們必須堅持到敵人撤退。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"그 말씀이 맞네요.","JPN":"そのとおりですね。","ENG":"You are right.","TWN":"你說的沒錯。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"다들 들었지?!","JPN":"みんな聞いたか！？","ENG":"You all heard!","TWN":"大家都聽到了吧？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"결전을 준비해라! 마왕군이 온다!","JPN":"決戦を準備しろ！　魔王軍が来る！","ENG":"Prepare for battle! The Demon Lord's army is coming!","TWN":"準備決戰！魔王軍來了！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHILD_ROOT_NPC_NULL","text":{"KOREA":"엄마… 엄마도 같이 가면 안 돼요?","JPN":"ママ……ママは一緒に行かないの？","ENG":"Mommy... Can't you come with?","TWN":"媽媽…你不能跟我一起去嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"괜찮아. 우리가 낙원으로 가기 위해, 너희를 먼저 보내는 것뿐이니까.","JPN":"大丈夫よ。みんなで楽園に行くために、あなたたちを先に送っているの。","ENG":"It's okay, sweety. You'll meet Mommy in the Promised Land, but it's just that you're going there first.","TWN":"沒事的。我們都可以去樂園的，只是先送你們過去。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"인사는 마쳤어요, 제사장님.","JPN":"挨拶が済みました、祭祀長。","ENG":"It's ready, High Priest.","TWN":"我話說完了，祭司長。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"...Very well.","TWN":"…嗯。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"귀염둥이, 이제 너만 남았어.","JPN":"可愛子ちゃん、アナタが最後よ。","ENG":"Cutie, you are the only one left.","TWN":"小可愛，現在就只剩下你了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아니, 싫어…!","JPN":"ちょっと、イヤ……！","ENG":"No, I'm not going...!","TWN":"不，不要…！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"마물이 오고 있다잖아! 어째서 내가 가야하는 건데?","JPN":"魔物が来てるんでしょう！？　どうしてあたしが行かないとダメなの？","ENG":"Didn't you hear that monsters are coming?! So why do I have to go?","TWN":"怪物要來了！為什麼要讓我離開？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그루터기에서 열 번째로 가벼운 아이가 너니까.","JPN":"切り株で10番目に軽いのはアナタだからよ。","ENG":"Because you are the Stump's tenth lightest child.","TWN":"因為你是木墩上第十個最輕的孩子。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이건 그루터기의 모두가 합의한 규칙이야.","JPN":"これは切り株のみんなで決めたことなの。","ENG":"This is a rule that everyone in the Stump has agreed to.","TWN":"這是木墩所有人共同決定的規則。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"싫어! 그건 내 동의도 없이 정한 규칙이잖아!","JPN":"イヤだ！　あたしはこんなこと、合意してない！","ENG":"NO! That's a rule that you all decided without me!","TWN":"不要！那也沒有經過我的同意！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"낙원에는 네가 필요해.","JPN":"楽園にはアナタが必要だわ。","ENG":"The Promised Land needs you.","TWN":"樂園需要你。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이 아이들을 모두 이끌어줄 수 있을 만큼, 강인한 사람이.","JPN":"この子どもたちを導く強い人が。","ENG":"We need a strong person to lead those children.","TWN":"一個能帶領這些孩子們的堅強的人。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그건 이곳도 마찬가지야!","JPN":"それはこっちも同じだよ！","ENG":"That goes for this place too!","TWN":"這裡也是一樣！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"우리가 꿈꾸던 낙원보다…! 이 동토에 내가 더 필요하다고!","JPN":"あたしの力を必要としてるのは楽園じゃない……！　凍土のほうだよ！","ENG":"The gelid lands need me more than... the Promised Land we dreamt of!","TWN":"比起我們夢想的樂園…！這片凍土更需要我！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내가 힘을 잃어서 그래?! 그래서 이제 내가 필요 없어진 거냐고!!","JPN":"あたしが力を失ったから！？　だからもうあたしは要らなくなったの！？","ENG":"Is it because I lost my power?! Is that why you don't need me anymore?!","TWN":"是因為我失去了力量嗎？！所以現在就不需要我了嗎！！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"아가씨…","JPN":"お嬢様……","ENG":"Miss Morgana...","TWN":"小姐…"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"네가 싫더라도, 규칙에 예외는 없어.","JPN":"アナタが嫌でも、もう決まったことよ。","ENG":"It does not matter if you do not like it. There are no exceptions to this rule.","TWN":"就算你不願意，規則也沒有例外。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"시간이 촉박하니, 계속 거부한다면 강제로라도 싣는 수 밖에.","JPN":"時間がないわ。この調子だと、強制的にでも乗せるしかないわね。","ENG":"Time is running out. If you keep refusing, I have no choice but to force you.","TWN":"時間緊迫，如果你繼續拒絕的話，只能強制執行了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"그럼 실례하겠습니다, 아가씨.","JPN":"では、失礼します。お嬢様。","ENG":"Then, excuse me, Miss Morgana.","TWN":"那就失禮了，小姐。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이거 놔! 난 안 가! 놓으라고!","JPN":"放して！　あたしは行かない！　放してよ！","ENG":"Hey, stop it! Let go of me! I said, let me go!","TWN":"放開我！我不走！放開！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐야 이거… 왜 힘을 줘도 안 풀리는 거야!!","JPN":"なにこれ……なんで力を入れても解けないの！！","ENG":"What...? Why can't I escape even using all my strength?!","TWN":"這是什麼…為什麼用力也解不開！！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린…!!!","JPN":"マーリン……！！","ENG":"Merlin...!!","TWN":"梅林…！！！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"감압 완료…! 시공간 위상차 조율 개시…!","JPN":"減圧完了……！　時空間位相差の調律開始……！","ENG":"Decompression complete...! Adjusting the spatial-temporal phase difference in coordinates...!","TWN":"減壓完成…！時空位相差調整開始…！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"남은 건 시간 문제로군요.","JPN":"あとは時間の問題ですね。","ENG":"Now, it is only a matter of time.","TWN":"剩下的就只是時間問題了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래.","JPN":"ええ。","ENG":"All right.","TWN":"好了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희는 이곳에 남아 아이들을 지켜주렴.","JPN":"アナタたちはここに残って子どもたちを守ってあげなさい。","ENG":"You stay here and protect the children.","TWN":"你們留在這裡保護孩子們吧。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"제사장님께선… 어떻게 하시려고요?","JPN":"祭祀長は……どうするおつもりですか？","ENG":"But... what about you, High Priest?","TWN":"祭司長…您打算怎麼做？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"불청객을 마당에 들일 생각은 없으니까.","JPN":"招かれざる客を入れるつもりはないからね。","ENG":"I do not intend on letting uninvited guests in.","TWN":"我可不打算讓不速之客闖進院子裡。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"버릇없는 괴물에게 가르침을 줘야지.","JPN":"礼儀のない化け物に教えてあげないと。","ENG":"I shall teach those rude monsters a lesson.","TWN":"該教訓一下不懂規矩的怪物。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};